import{_ as o,o as i,c as l,a4 as t}from"./chunks/framework.CtnSHCpE.js";const m=JSON.parse('{"title":"","description":"","frontmatter":{},"headers":[],"relativePath":"Guides/recommended.md","filePath":"Guides/recommended.md","lastUpdated":1748415123000}'),n={name:"Guides/recommended.md"};function a(r,e,c,d,s,g){return i(),l("div",null,[...e[0]||(e[0]=[t('<p>This guide provides a recommended set of open source tools for various roles within the zopen community. Each role, ranging from system administrators to AI engineers has unique needs, and these tools aim to boost productivity, enhance security, and simplify workflows on the mainframe. These tools can be installed, updated and managed via <a href="/meta/Guides/ThePackageManager">zopen package manager</a>.</p><h2 id="_1-system-administrator" tabindex="-1">1. <strong>System Administrator</strong> <a class="header-anchor" href="#_1-system-administrator" aria-label="Permalink to &quot;1. **System Administrator**&quot;">​</a></h2><ul><li><strong>Core System Tools</strong>: <ul><li><code>coreutils</code> - Essential core utilities (e.g., ls, cat) for daily operations. Recommended if you require additional function over z/OS Native /bin tools.</li><li><code>util-linux</code> - Common utilities (e.g., whereis - to locate files quickly).</li><li><code>moreutils</code> - Additional utilities such as sponge, parallel, and more. See this <a href="https://rentes.github.io/unix/utilities/2015/07/27/moreutils-package/" target="_blank" rel="noreferrer">blog</a> for more details.</li><li><code>findutils</code>, <code>grep</code>, <code>sed</code>, <code>diff</code> - GNU based utilities with additional function over /bin tools.</li></ul></li><li><strong>Networking and Security</strong>: <ul><li><code>openssh</code> - Secure remote login and file transfer (includes sftp, ssh, and ssh-copy-id (great for copying an ssh key to another machine quickly)).</li><li><code>curl</code>, <code>wget</code> - Tools to fetch files over HTTP/HTTPS.</li><li><code>openssl</code> - Encryption and security client and library.</li><li><code>sudo</code> - Privilege escalation for executing commands.</li></ul></li><li><strong>System Configuration and Management</strong>: <ul><li><code>c3270</code> - c3270 emulator to access ISPF/TSO via z/OS UNIX</li><li><code>bash</code> - Shell scripting and command interpreter.</li><li><code>logrotate</code> - Automatic rotation and compression of logs.</li><li><code>tmux</code> and <code>screen</code> - Terminal multiplexer for managing sessions.</li><li><code>tree</code> - Directory and file structure visualization.</li><li>(WIP) <code>rsync</code> - File synchronization and transfer.</li></ul></li><li><strong>Monitoring</strong>: <ul><li><code>prometheus</code> - Metric-based system and application monitoring.</li><li><code>victoriametrics</code> - High-performance database for time-series metrics.</li><li><code>grafana</code> - Visualization tool for metrics.</li></ul></li><li><strong>File Management</strong>: <ul><li><code>ncdu</code> - Disk usage analyzer to detect files and dirs using up disk space.</li><li><code>zip</code>, <code>unzip</code>, <code>gzip</code>, <code>tar</code>, <code>bzip2</code>, <code>xz</code>, <code>zstd</code> - Compression and archiving tools for backup or archiving data.</li></ul></li><li><strong>zopen</strong>: <ul><li><code>meta</code> - Package manager to install and manage tools.</li><li><code>zopen audit</code> - Security command to check for vulnerabilities in packages.</li></ul></li></ul><h2 id="_2-application-developer" tabindex="-1">2. <strong>Application Developer</strong> <a class="header-anchor" href="#_2-application-developer" aria-label="Permalink to &quot;2. **Application Developer**&quot;">​</a></h2><ul><li><strong>Core System Tools</strong>: <ul><li><code>coreutils</code> - Essential core utilities (e.g., ls, cat) for daily operations. Recommended if you require additional function over z/OS Native /bin tools.</li><li><code>util-linux</code> - Common utilities (e.g., whereis - to locate files quickly).</li><li><code>moreutils</code> - Additional utilities such as sponge, parallel, and more. See this <a href="https://rentes.github.io/unix/utilities/2015/07/27/moreutils-package/" target="_blank" rel="noreferrer">blog</a> for more details.</li><li><code>findutils</code>, <code>grep</code>, <code>sed</code>, <code>diff</code> - GNU based utilities with additional function over /bin tools.</li></ul></li><li><strong>Coding and Compilation</strong>: <ul><li><code>cmake</code> - (Recommended for new projects) - Build automation tool that generates build system files for Make, Ninja and more.</li><li><code>ninja</code> - Very fast build systems for compiling projects.</li><li><code>make</code> - Build systems for compiling projects.</li><li><code>m4</code> - Macro processor for generating code templates.</li><li><code>autoconf</code>, <code>automake</code>, <code>pkgconfig</code> - Tools for configuring software builds.</li></ul></li><li><strong>Languages</strong><ul><li><code>lua</code>, <code>perl</code> - Extend functionality with embedded lua or write automation scripts using perl.</li></ul></li><li><strong>Libraries</strong>: <ul><li><code>zlib</code> - Compression library.</li><li><code>sqlite</code> - Embedded database library</li><li><code>libgpgerror</code>, <code>libgcrypt</code> - Cryptographic libraries for signing content.</li><li><code>libpcre</code> - Library for regex</li><li><code>libxml2</code> - XML library</li><li><code>cjson</code> - C JSON parsing library (used in Libdio)</li><li><code>protobuf</code> - Protocol Buffers for data serialization.</li></ul></li><li><strong>Text Editing</strong>: <ul><li><code>vim</code>, <code>nano</code>, <code>emacs</code> - Popular text editors for coding.</li></ul></li><li><strong>Data processing</strong>: <ul><li><code>jq</code>, <code>yq</code> - JSON and YAML processing tools.</li></ul></li><li><strong>Version Control</strong>: <ul><li><code>git</code> - Git source control</li><li><code>git-lfs</code> - Git large file support.</li><li><code>gitlabcli</code> - Command-line interface for GitLab.</li><li><code>githubcli</code> - Command-line interface for Github.</li></ul></li><li><strong>Documentation</strong>: <ul><li><code>doxygen</code> - Documentation generation from source code.</li><li><code>help2man</code>, <code>man-db</code> - Tools for creating and managing man pages.</li></ul></li><li><strong>zopen</strong>: <ul><li><code>meta</code> - Package manager for installing development tools.</li></ul></li></ul><h2 id="_3-devops-ci-cd-engineer" tabindex="-1">3. <strong>DevOps / CI/CD Engineer</strong> <a class="header-anchor" href="#_3-devops-ci-cd-engineer" aria-label="Permalink to &quot;3. **DevOps / CI/CD Engineer**&quot;">​</a></h2><ul><li><strong>Automation</strong>: <ul><li><code>buildkite</code> - Continuous integration agent</li><li><code>github-runner</code> - Gitlab Continuous integration</li></ul></li><li><strong>Version Control &amp; Collaboration</strong>: <ul><li><code>git</code>, <code>gitlabcli</code>, <code>githubcli</code> - Version control and GitHub/GitLab management.</li></ul></li><li><strong>Networking and Security</strong>: <ul><li><code>openssh</code>, <code>cosign</code>, <code>gpg</code> - Secure access and container signing.</li><li><code>ntbtls</code>, <code>openssl</code> - Encryption and network security libraries.</li></ul></li><li><strong>Monitoring and Logging</strong>: <ul><li><code>prometheus</code>, <code>grafana</code>, <code>victoriametrics</code> - Monitoring and visualization tools.</li><li><code>logrotate</code> - Log file management.</li></ul></li><li><strong>zopen</strong>: <ul><li><code>meta</code> - Comprehensive package manager for CI/CD tools.</li></ul></li></ul><h2 id="_4-ai-engineer" tabindex="-1">4. <strong>AI Engineer</strong> <a class="header-anchor" href="#_4-ai-engineer" aria-label="Permalink to &quot;4. **AI Engineer**&quot;">​</a></h2><ul><li><strong>Data Handling and Preprocessing</strong>: <ul><li><code>duckdb</code> - In-process SQL database for data analytics.</li><li><code>jq</code>, <code>yq</code> - JSON and YAML processing tools.</li></ul></li><li><strong>Machine Learning Libraries</strong>: <ul><li><code>llamacpp</code> - Lightweight machine learning library.</li></ul></li><li><strong>Version Control</strong>: <ul><li><code>git</code>, <code>git-lfs</code>, <code>githubcli</code> - Version control and GitHub management.</li></ul></li><li><strong>zopen</strong>: <ul><li><code>meta</code> - Package manager to manage machine learning and AI tools.</li></ul></li></ul><h2 id="_5-project-manager" tabindex="-1">5. <strong>Project Manager</strong> <a class="header-anchor" href="#_5-project-manager" aria-label="Permalink to &quot;5. **Project Manager**&quot;">​</a></h2><ul><li><strong>Collaboration &amp; Communication</strong>: <ul><li><code>githubcli</code>, <code>gitlabcli</code> - GitHub and GitLab command-line interfaces.</li></ul></li><li><strong>Version Control</strong>: <ul><li><code>git</code>, <code>git-lfs</code> - Version control for project files.</li></ul></li><li><strong>Workflow Automation</strong>: <ul><li><code>bash</code>, <code>curl</code>- Tools for scripting and automating tasks.</li></ul></li><li><strong>Monitoring</strong>: <ul><li><code>prometheus</code>, <code>grafana</code> - Tools for tracking project metrics.</li></ul></li><li><strong>zopen</strong>: <ul><li><code>meta</code> - Package manager to install and manage project management tools.</li></ul></li></ul>',11)])])}const p=o(n,[["render",a]]);export{m as __pageData,p as default};
